    /// <inheritdoc/>
    public override bool Equals(object? obj)
    {
        return
            (obj is IJsonElement value && Equals(new Schema(value.ParentDocument, value.ParentDocumentIndex))) ||
            (obj is null && this.IsNull());
    }

    /// <summary>
    /// Equality comparison.
    /// </summary>
    /// <param name="other">The other item with which to compare.</param>
    /// <returns><see langword="true"/> if the values were equal.</returns>
    public bool Equals<T>(in T other)
        where T : struct, IJsonElement
    {
        return JsonElementHelpers.DeepEquals(this, other);
    }

    /// <inheritdoc/>
    public void WriteTo(Utf8JsonWriter writer)
    {
        CheckValidInstance();
        _parent.WriteElementTo(_idx, writer);
    }

    /// <inheritdoc/>
    public override int GetHashCode()
    {
        if (_parent == null)
        {
            return 0;
        }

        return _parent.GetHashCode(_idx);
    }

    /// <inheritdoc/>
    public string ToString(string? format, IFormatProvider? formatProvider)
    {
        CheckValidInstance();

        return _parent.ToString(_idx, format, formatProvider);
    }

    /// <inheritdoc/>
    public bool TryFormat(Span<char> destination, out int charsWritten, ReadOnlySpan<char> format, IFormatProvider? provider)
    {
        CheckValidInstance();

        return _parent.TryFormat(_idx, destination, out charsWritten, format, provider);
    }

    /// <inheritdoc/>
    public bool TryFormat(Span<byte> utf8Destination, out int bytesWritten, ReadOnlySpan<char> format, IFormatProvider? provider)
    {
        CheckValidInstance();

        return _parent.TryFormat(_idx, utf8Destination, out bytesWritten, format, provider);
    }
    /// <inheritdoc/>
    public override string ToString()
    {
        if (_parent is null)
        {
            return string.Empty;
        }

        return _parent.ToString(_idx);
    }

    /// <summary>
    /// Evaluate this instance against the JSON Schema for this type.
    /// </summary>
    /// <params name="resultsCollector">The (optional) results collector.</params>
    /// <returns><see langword="true" /> if the instance evaluates against the schema.</returns>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    public bool EvaluateSchema(IJsonSchemaResultsCollector? resultsCollector = null)
    {
        return JsonSchema.Evaluate(_parent, _idx, resultsCollector);
    }

    private void CheckValidInstance()
    {
        if (_parent == null)
        {
            throw new InvalidOperationException();
        }
    }

    /// <inheritdoc/>
    void IJsonElement.CheckValidInstance() => CheckValidInstance();

#if NET
    static Schema IJsonElement<Schema>.CreateInstance(IJsonDocument parentDocument, int parentDocumentIndex) => new(parentDocument, parentDocumentIndex);
#endif

